-- EKBALLO ACADEMY · Migra 181 devocionais existentes pra versão NAA
-- (Nova Almeida Atualizada). Textos buscados via bolls.life/NAA.
-- Script reproducível: scripts/migrar-devocionais-naa.mjs

update devocional_anual set versiculo_texto = 'E, assim, se alguém está em Cristo, é nova criatura; as coisas antigas já passaram; eis que se fizeram novas.', versiculo_versao = 'NAA' where dia_ano = 1;
update devocional_anual set versiculo_texto = 'Irmãos, quanto a mim, não julgo havê-lo alcançado, mas uma coisa faço: esquecendo-me das coisas que ficam para trás e avançando para as que estão diante de mim, prossigo para o alvo, para o prêmio da soberana vocação de Deus em Cristo Jesus.', versiculo_versao = 'NAA' where dia_ano = 2;
update devocional_anual set versiculo_texto = 'As misericórdias do SENHOR são a causa de não sermos consumidos, porque as suas misericórdias não têm fim; renovam-se cada manhã. Grande é a tua fidelidade.', versiculo_versao = 'NAA' where dia_ano = 3;
update devocional_anual set versiculo_texto = '“Não fiquem lembrando das coisas passadas, nem pensem nas coisas antigas. Eis que faço uma coisa nova. Agora mesmo ela está saindo à luz. Será que vocês não o percebem? Eis que porei um caminho no deserto e rios nos lugares áridos.', versiculo_versao = 'NAA' where dia_ano = 4;
update devocional_anual set versiculo_texto = 'Cria em mim, ó Deus, um coração puro e renova dentro de mim um espírito inabalável.', versiculo_versao = 'NAA' where dia_ano = 5;
update devocional_anual set versiculo_texto = 'Eu lhes darei um coração novo e porei dentro de vocês um espírito novo. Tirarei de vocês o coração de pedra e lhes darei um coração de carne.', versiculo_versao = 'NAA' where dia_ano = 6;
update devocional_anual set versiculo_texto = 'E não vivam conforme os padrões deste mundo, mas deixem que Deus os transforme pela renovação da mente, para que possam experimentar qual é a boa, agradável e perfeita vontade de Deus.', versiculo_versao = 'NAA' where dia_ano = 7;
update devocional_anual set versiculo_texto = 'Tudo tem o seu tempo determinado, e há tempo para todo propósito debaixo do céu:', versiculo_versao = 'NAA' where dia_ano = 8;
update devocional_anual set versiculo_texto = 'Confie no SENHOR de todo o seu coração e não se apoie no seu próprio entendimento. Reconheça o SENHOR em todos os seus caminhos, e ele endireitará as suas veredas.', versiculo_versao = 'NAA' where dia_ano = 9;
update devocional_anual set versiculo_texto = 'Eu é que sei que pensamentos tenho a respeito de vocês, diz o SENHOR. São pensamentos de paz e não de mal, para dar-lhes um futuro e uma esperança.', versiculo_versao = 'NAA' where dia_ano = 10;
update devocional_anual set versiculo_texto = '— Venham a mim todos vocês que estão cansados e sobrecarregados, e eu os aliviarei. Tomem sobre vocês o meu jugo e aprendam de mim, porque sou manso e humilde de coração; e vocês acharão descanso para a sua alma. Porque o meu jugo é suave, e o meu fardo é leve.', versiculo_versao = 'NAA' where dia_ano = 11;
update devocional_anual set versiculo_texto = 'Se, pois, o Filho os libertar, vocês serão verdadeiramente livres.', versiculo_versao = 'NAA' where dia_ano = 12;
update devocional_anual set versiculo_texto = 'Salmo de Davi O SENHOR é o meu pastor; nada me faltará. Ele me faz repousar em pastos verdejantes. Leva-me para junto das águas de descanso; refrigera-me a alma. Guia-me pelas veredas da justiça por amor do seu nome.', versiculo_versao = 'NAA' where dia_ano = 13;
update devocional_anual set versiculo_texto = 'Estou certo de que aquele que começou boa obra em vocês há de completá-la até o Dia de Cristo Jesus.', versiculo_versao = 'NAA' where dia_ano = 14;
update devocional_anual set versiculo_texto = 'Mas busquem em primeiro lugar o Reino de Deus e a sua justiça, e todas estas coisas lhes serão acrescentadas.', versiculo_versao = 'NAA' where dia_ano = 15;
update devocional_anual set versiculo_texto = 'Entregue o seu caminho ao SENHOR, confie nele, e o mais ele fará.', versiculo_versao = 'NAA' where dia_ano = 16;
update devocional_anual set versiculo_texto = 'De tudo o que se deve guardar, guarde bem o seu coração, porque dele procedem as fontes da vida.', versiculo_versao = 'NAA' where dia_ano = 17;
update devocional_anual set versiculo_texto = 'mas os que esperam no SENHOR renovam as suas forças, sobem com asas como águias, correm e não se cansam, caminham e não se fatigam.', versiculo_versao = 'NAA' where dia_ano = 18;
update devocional_anual set versiculo_texto = 'Se confessarmos os nossos pecados, ele é fiel e justo para nos perdoar os pecados e nos purificar de toda injustiça.', versiculo_versao = 'NAA' where dia_ano = 19;
update devocional_anual set versiculo_texto = 'Eu o instruirei e lhe ensinarei o caminho que você deve seguir; e, sob as minhas vistas, lhe darei conselho.', versiculo_versao = 'NAA' where dia_ano = 20;
update devocional_anual set versiculo_texto = 'Entregue as suas obras ao SENHOR, e o que você tem planejado se realizará.', versiculo_versao = 'NAA' where dia_ano = 21;
update devocional_anual set versiculo_texto = 'Sonda-me, ó Deus, e conhece o meu coração, prova-me e conhece os meus pensamentos; vê se há em mim algum caminho mau e guia-me pelo caminho eterno.', versiculo_versao = 'NAA' where dia_ano = 22;
update devocional_anual set versiculo_texto = 'Cheguem perto de Deus, e ele se chegará a vocês. Limpem as mãos, pecadores! E vocês que são indecisos, purifiquem o coração.', versiculo_versao = 'NAA' where dia_ano = 23;
update devocional_anual set versiculo_texto = 'Espere no SENHOR. Anime-se, e fortifique-se o seu coração; espere, pois, no SENHOR.', versiculo_versao = 'NAA' where dia_ano = 24;
update devocional_anual set versiculo_texto = 'Lancem sobre ele todas as suas ansiedades, porque ele cuida de vocês.', versiculo_versao = 'NAA' where dia_ano = 25;
update devocional_anual set versiculo_texto = '— Peçam e lhes será dado; busquem e acharão; batam, e a porta será aberta para vocês. Pois todo o que pede recebe; o que busca encontra; e, a quem bate, a porta será aberta.', versiculo_versao = 'NAA' where dia_ano = 26;
update devocional_anual set versiculo_texto = 'Agora, pois, já não existe nenhuma condenação para os que estão em Cristo Jesus.', versiculo_versao = 'NAA' where dia_ano = 27;
update devocional_anual set versiculo_texto = 'Para a liberdade foi que Cristo nos libertou. Por isso, permaneçam firmes e não se submetam, de novo, a jugo de escravidão.', versiculo_versao = 'NAA' where dia_ano = 28;
update devocional_anual set versiculo_texto = 'Pois quem despreza o dia dos humildes começos, esse ficará alegre ao ver o prumo nas mãos de Zorobabel. Aqueles sete olhos são os olhos do SENHOR, que percorrem toda a terra.', versiculo_versao = 'NAA' where dia_ano = 29;
update devocional_anual set versiculo_texto = 'Portanto, também nós, visto que temos a rodear-nos tão grande nuvem de testemunhas, livremo-nos de todo peso e do pecado que tão firmemente se apega a nós e corramos com perseverança a carreira que nos está proposta, olhando firmemente para o Autor e Consumador da fé, Jesus, o qual, em troca da alegria que lhe estava proposta, suportou a cruz, sem se importar com a vergonha, e agora está sentado à direita do trono de Deus.', versiculo_versao = 'NAA' where dia_ano = 30;
update devocional_anual set versiculo_texto = 'Não se gabe do dia de amanhã, porque você não sabe o que ele trará à luz.', versiculo_versao = 'NAA' where dia_ano = 31;
update devocional_anual set versiculo_texto = 'Jesus respondeu: — “Ame o Senhor, seu Deus, de todo o seu coração, de toda a sua alma e de todo o seu entendimento.”', versiculo_versao = 'NAA' where dia_ano = 32;
update devocional_anual set versiculo_texto = 'Porém o SENHOR disse a Samuel: — Não olhe para a sua aparência nem para a sua altura, porque eu o rejeitei. Porque o SENHOR não vê como o ser humano vê. O ser humano vê o exterior, porém o SENHOR vê o coração.', versiculo_versao = 'NAA' where dia_ano = 33;
update devocional_anual set versiculo_texto = 'Eis que te agradas da verdade no íntimo e no oculto me fazes conhecer a sabedoria.', versiculo_versao = 'NAA' where dia_ano = 34;
update devocional_anual set versiculo_texto = 'Quem tenho eu no céu além de ti? E quem poderia eu querer na terra além de ti? Ainda que a minha carne e o meu coração desfaleçam, Deus é a fortaleza do meu coração e a minha herança para sempre.', versiculo_versao = 'NAA' where dia_ano = 35;
update devocional_anual set versiculo_texto = '— Bem-aventurados os limpos de coração, porque verão a Deus.', versiculo_versao = 'NAA' where dia_ano = 36;
update devocional_anual set versiculo_texto = 'Quem encobre as suas transgressões jamais prosperará; mas o que as confessa e abandona alcançará misericórdia.', versiculo_versao = 'NAA' where dia_ano = 37;
update devocional_anual set versiculo_texto = 'A pessoa boa tira o bem do bom tesouro do coração, e a pessoa má tira o mal do mau tesouro; porque a boca fala do que está cheio o coração.', versiculo_versao = 'NAA' where dia_ano = 38;
update devocional_anual set versiculo_texto = 'Ensina-me, SENHOR, o teu caminho, e andarei na tua verdade; põe em meu coração o desejo de temer o teu nome.', versiculo_versao = 'NAA' where dia_ano = 39;
update devocional_anual set versiculo_texto = '— Ai de vocês, escribas e fariseus, hipócritas, porque vocês limpam o exterior do copo e do prato, mas estes, por dentro, estão cheios de roubo e de glutonaria! Fariseu cego! Limpe primeiro o interior do copo, para que também o seu exterior fique limpo!', versiculo_versao = 'NAA' where dia_ano = 40;
update devocional_anual set versiculo_texto = 'As palavras dos meus lábios e o meditar do meu coração sejam agradáveis na tua presença, SENHOR, rocha minha e redentor meu!', versiculo_versao = 'NAA' where dia_ano = 41;
update devocional_anual set versiculo_texto = 'Porque a palavra de Deus é viva e eficaz, e mais cortante do que qualquer espada de dois gumes, e penetra até o ponto de dividir alma e espírito, juntas e medulas, e é apta para julgar os pensamentos e propósitos do coração.', versiculo_versao = 'NAA' where dia_ano = 42;
update devocional_anual set versiculo_texto = 'Meu filho, preste bem atenção no que eu digo, e que os seus olhos se agradem dos meus caminhos.', versiculo_versao = 'NAA' where dia_ano = 43;
update devocional_anual set versiculo_texto = 'Quem subirá ao monte do SENHOR? Quem há de permanecer no seu santo lugar? O que é limpo de mãos e puro de coração, que não entrega a sua alma à falsidade, nem faz juramentos com a intenção de enganar.', versiculo_versao = 'NAA' where dia_ano = 44;
update devocional_anual set versiculo_texto = '“Enganoso é o coração, mais do que todas as coisas, e desesperadamente corrupto. Quem poderá entendê-lo? Eu, o SENHOR, sondo o coração. Eu provo os pensamentos, para dar a cada um segundo os seus caminhos, segundo o fruto das suas ações.”', versiculo_versao = 'NAA' where dia_ano = 45;
update devocional_anual set versiculo_texto = 'Porque, onde estiver o seu tesouro, aí estará também o seu coração.', versiculo_versao = 'NAA' where dia_ano = 46;
update devocional_anual set versiculo_texto = 'Guardo a tua palavra no meu coração para não pecar contra ti.', versiculo_versao = 'NAA' where dia_ano = 47;
update devocional_anual set versiculo_texto = 'Mas, ao orar, entre no seu quarto e, fechada a porta, ore ao seu Pai, que está em secreto. E o seu Pai, que vê em secreto, lhe dará a recompensa.', versiculo_versao = 'NAA' where dia_ano = 48;
update devocional_anual set versiculo_texto = 'Tenho, porém, contra você o seguinte: você abandonou o seu primeiro amor. Lembre-se, pois, de onde você caiu. Arrependa-se e volte à prática das primeiras obras. Se você não se arrepender, virei até você e tirarei o seu candelabro do lugar dele.', versiculo_versao = 'NAA' where dia_ano = 49;
update devocional_anual set versiculo_texto = 'Pois quero misericórdia, e não sacrifício; conhecimento de Deus, mais do que holocaustos.”', versiculo_versao = 'NAA' where dia_ano = 50;
update devocional_anual set versiculo_texto = 'Ao mestre de canto. Salmo didático dos filhos de Corá Assim como a corça suspira pelas correntes das águas, assim, por ti, ó Deus, suspira a minha alma. A minha alma tem sede de Deus, do Deus vivo. Quando irei e me apresentarei diante da face de Deus?', versiculo_versao = 'NAA' where dia_ano = 51;
update devocional_anual set versiculo_texto = 'Salmo de Davi, quando estava no deserto de Judá Ó Deus, tu és o meu Deus; eu te busco ansiosamente. A minha alma tem sede de ti; meu corpo te almeja, como terra árida, exausta e sem água.', versiculo_versao = 'NAA' where dia_ano = 52;
update devocional_anual set versiculo_texto = 'Tenho o SENHOR sempre diante de mim; estando ele à minha direita, não serei abalado.', versiculo_versao = 'NAA' where dia_ano = 53;
update devocional_anual set versiculo_texto = 'Todos os caminhos de uma pessoa são puros aos seus próprios olhos, mas o SENHOR sonda o espírito.', versiculo_versao = 'NAA' where dia_ano = 54;
update devocional_anual set versiculo_texto = 'Jesus respondeu: — Bem profetizou Isaías a respeito de vocês, hipócritas, como está escrito: “Este povo me honra com os lábios, mas o seu coração está longe de mim.', versiculo_versao = 'NAA' where dia_ano = 55;
update devocional_anual set versiculo_texto = 'Graças te dou, visto que de modo assombrosamente maravilhoso me formaste; as tuas obras são admiráveis, e a minha alma o sabe muito bem.', versiculo_versao = 'NAA' where dia_ano = 56;
update devocional_anual set versiculo_texto = 'Desde os dias dos seus pais, vocês se afastaram dos meus estatutos e não os guardaram. Voltem para mim, e eu voltarei para vocês, diz o SENHOR dos Exércitos. Mas vocês perguntam: “Como havemos de voltar?”', versiculo_versao = 'NAA' where dia_ano = 57;
update devocional_anual set versiculo_texto = 'mas apenas uma é necessária. Maria escolheu a boa parte, e esta não lhe será tirada.', versiculo_versao = 'NAA' where dia_ano = 58;
update devocional_anual set versiculo_texto = 'Ao meu coração me ocorre: “Busquem a minha presença.” Buscarei, pois, SENHOR, a tua presença.', versiculo_versao = 'NAA' where dia_ano = 59;
update devocional_anual set versiculo_texto = 'Mas, se vocês não quiserem servir o SENHOR, escolham hoje a quem vão servir: se os deuses a quem os pais de vocês serviram do outro lado do Eufrates ou os deuses dos amorreus em cuja terra vocês estão morando. Eu e a minha casa serviremos o SENHOR.', versiculo_versao = 'NAA' where dia_ano = 60;
update devocional_anual set versiculo_texto = 'Ensine a criança no caminho em que deve andar, e ainda quando for velho não se desviará dele.', versiculo_versao = 'NAA' where dia_ano = 61;
update devocional_anual set versiculo_texto = 'Maridos, que cada um de vocês ame a sua esposa, como também Cristo amou a igreja e se entregou por ela,', versiculo_versao = 'NAA' where dia_ano = 62;
update devocional_anual set versiculo_texto = 'Esposas, que cada uma de vocês se sujeite a seu próprio marido, como ao Senhor; porque o marido é o cabeça da esposa, como também Cristo é o cabeça da igreja, sendo ele próprio o salvador do corpo. Como, porém, a igreja está sujeita a Cristo, assim também a esposa se sujeite em tudo ao seu próprio marido.', versiculo_versao = 'NAA' where dia_ano = 63;
update devocional_anual set versiculo_texto = 'Estas palavras que hoje lhe ordeno estarão no seu coração. Você as inculcará a seus filhos, e delas falará quando estiver sentado em sua casa, andando pelo caminho, ao deitar-se e ao levantar-se.', versiculo_versao = 'NAA' where dia_ano = 64;
update devocional_anual set versiculo_texto = 'Cântico de peregrinação. De Salomão Se o SENHOR não edificar a casa, em vão trabalham os que a edificam. Se o SENHOR não guardar a cidade, em vão vigia a sentinela.', versiculo_versao = 'NAA' where dia_ano = 65;
update devocional_anual set versiculo_texto = 'Herança do SENHOR são os filhos; o fruto do ventre, seu galardão.', versiculo_versao = 'NAA' where dia_ano = 66;
update devocional_anual set versiculo_texto = '— Honre o seu pai e a sua mãe, para que você tenha uma longa vida na terra que o SENHOR, seu Deus, lhe dá.', versiculo_versao = 'NAA' where dia_ano = 67;
update devocional_anual set versiculo_texto = 'Mulher virtuosa, quem a achará? O seu valor muito excede o de finas joias. O coração do seu marido confia nela, e não haverá falta de ganho. Ela lhe faz bem e não mal, todos os dias da sua vida.', versiculo_versao = 'NAA' where dia_ano = 68;
update devocional_anual set versiculo_texto = 'Coroa dos velhos são os filhos dos filhos; e a glória dos filhos são os pais.', versiculo_versao = 'NAA' where dia_ano = 69;
update devocional_anual set versiculo_texto = 'Pais, não irritem os seus filhos, para que eles não fiquem desanimados.', versiculo_versao = 'NAA' where dia_ano = 70;
update devocional_anual set versiculo_texto = 'Cântico de peregrinação. De Davi Oh! Como é bom e agradável viverem unidos os irmãos!', versiculo_versao = 'NAA' where dia_ano = 71;
update devocional_anual set versiculo_texto = 'De modo que já não são mais dois, porém uma só carne. Portanto, que ninguém separe o que Deus ajuntou.', versiculo_versao = 'NAA' where dia_ano = 72;
update devocional_anual set versiculo_texto = 'O que retém a vara odeia o seu filho; quem o ama, este o disciplina desde cedo.', versiculo_versao = 'NAA' where dia_ano = 73;
update devocional_anual set versiculo_texto = 'E, arrumando-se, foi para o seu pai. — Vinha ele ainda longe, quando seu pai o avistou e, compadecido dele, correndo, o abraçou e beijou.', versiculo_versao = 'NAA' where dia_ano = 74;
update devocional_anual set versiculo_texto = 'Seus filhos se levantam e a chamam de bem-aventurada; seu marido a louva, dizendo:', versiculo_versao = 'NAA' where dia_ano = 75;
update devocional_anual set versiculo_texto = 'Aquele que perturba a sua casa herdará o vento, e o insensato será servo do sábio de coração.', versiculo_versao = 'NAA' where dia_ano = 76;
update devocional_anual set versiculo_texto = 'Mas Jesus, sabendo o que eles pensavam, disse-lhes: — Todo reino dividido contra si mesmo ficará deserto, e toda cidade ou casa dividida contra si mesma não subsistirá.', versiculo_versao = 'NAA' where dia_ano = 77;
update devocional_anual set versiculo_texto = 'Sua esposa, no interior de sua casa, será como a videira frutífera; seus filhos serão como rebentos da oliveira ao redor da sua mesa.', versiculo_versao = 'NAA' where dia_ano = 78;
update devocional_anual set versiculo_texto = 'Maridos, vocês, igualmente, vivam a vida comum do lar com discernimento, dando honra à esposa, por ser a parte mais frágil e por ser coerdeira da mesma graça da vida. Agindo assim, as orações de vocês não serão interrompidas.', versiculo_versao = 'NAA' where dia_ano = 79;
update devocional_anual set versiculo_texto = 'Lembro da sua fé sem fingimento, a mesma que, primeiramente, habitou em sua avó Loide e em sua mãe Eunice, e estou certo de que habita também em você.', versiculo_versao = 'NAA' where dia_ano = 80;
update devocional_anual set versiculo_texto = 'A mulher sábia edifica a sua casa, mas a insensata a derruba com as próprias mãos.', versiculo_versao = 'NAA' where dia_ano = 81;
update devocional_anual set versiculo_texto = 'a fim de instruírem as jovens recém-casadas a amar o marido e os filhos, a serem sensatas, puras, boas donas de casa, bondosas, sujeitas ao marido, para que a palavra de Deus não seja difamada.', versiculo_versao = 'NAA' where dia_ano = 82;
update devocional_anual set versiculo_texto = 'Façam aos outros o mesmo que vocês querem que eles façam a vocês.', versiculo_versao = 'NAA' where dia_ano = 83;
update devocional_anual set versiculo_texto = 'Pelo contrário, sejam bondosos e compassivos uns para com os outros, perdoando uns aos outros, como também Deus, em Cristo, perdoou vocês.', versiculo_versao = 'NAA' where dia_ano = 84;
update devocional_anual set versiculo_texto = 'A resposta branda desvia o furor, mas a palavra dura suscita a ira.', versiculo_versao = 'NAA' where dia_ano = 85;
update devocional_anual set versiculo_texto = 'Com a sabedoria se constrói a casa, e com a inteligência ela se firma; pelo conhecimento os seus cômodos se encherão de todo tipo de bens, preciosos e agradáveis.', versiculo_versao = 'NAA' where dia_ano = 86;
update devocional_anual set versiculo_texto = '— Porque, se perdoarem aos outros as ofensas deles, também o Pai de vocês, que está no céu, perdoará vocês; se, porém, não perdoarem aos outros as ofensas deles, também o Pai de vocês não perdoará as ofensas de vocês.', versiculo_versao = 'NAA' where dia_ano = 87;
update devocional_anual set versiculo_texto = 'Se alguém disser: “Amo a Deus”, mas odiar o seu irmão, esse é mentiroso. Pois quem não ama o seu irmão, a quem vê, não pode amar a Deus, a quem não vê.', versiculo_versao = 'NAA' where dia_ano = 88;
update devocional_anual set versiculo_texto = '“Honre o seu pai e a sua mãe”, que é o primeiro mandamento com promessa, “para que tudo corra bem com você, e você tenha uma longa vida sobre a terra”.', versiculo_versao = 'NAA' where dia_ano = 89;
update devocional_anual set versiculo_texto = 'Então Pedro, aproximando-se, perguntou a Jesus: — Senhor, até quantas vezes meu irmão pecará contra mim, que eu lhe perdoe? Até sete vezes? Jesus respondeu: — Não digo a você que perdoe até sete vezes, mas até setenta vezes sete.', versiculo_versao = 'NAA' where dia_ano = 90;
update devocional_anual set versiculo_texto = 'logo, já não sou eu quem vive, mas Cristo vive em mim. E esse viver que agora tenho na carne, vivo pela fé no Filho de Deus, que me amou e se entregou por mim.', versiculo_versao = 'NAA' where dia_ano = 91;
update devocional_anual set versiculo_texto = 'Jesus dizia a todos: — Se alguém quer vir após mim, negue a si mesmo, dia a dia tome a sua cruz e siga-me.', versiculo_versao = 'NAA' where dia_ano = 92;
update devocional_anual set versiculo_texto = 'Fomos sepultados com ele na morte pelo batismo, para que, como Cristo foi ressuscitado dentre os mortos pela glória do Pai, assim também nós andemos em novidade de vida.', versiculo_versao = 'NAA' where dia_ano = 93;
update devocional_anual set versiculo_texto = 'Certamente a palavra da cruz é loucura para os que se perdem, mas para nós, que somos salvos, ela é poder de Deus.', versiculo_versao = 'NAA' where dia_ano = 94;
update devocional_anual set versiculo_texto = 'Portanto, se vocês foram ressuscitados juntamente com Cristo, busquem as coisas lá do alto, onde Cristo vive, assentado à direita de Deus.', versiculo_versao = 'NAA' where dia_ano = 95;
update devocional_anual set versiculo_texto = 'olhando firmemente para o Autor e Consumador da fé, Jesus, o qual, em troca da alegria que lhe estava proposta, suportou a cruz, sem se importar com a vergonha, e agora está sentado à direita do trono de Deus.', versiculo_versao = 'NAA' where dia_ano = 96;
update devocional_anual set versiculo_texto = 'Por volta de três horas da tarde, Jesus clamou em alta voz, dizendo: — Eli, Eli, lemá sabactani? — Isso quer dizer: “Deus meu, Deus meu, por que me desamparaste?”', versiculo_versao = 'NAA' where dia_ano = 97;
update devocional_anual set versiculo_texto = 'Ele não está aqui; ressuscitou, como tinha dito. Venham ver onde ele jazia.', versiculo_versao = 'NAA' where dia_ano = 98;
update devocional_anual set versiculo_texto = '“Onde está, ó morte, a sua vitória? Onde está, ó morte, o seu aguilhão?”', versiculo_versao = 'NAA' where dia_ano = 99;
update devocional_anual set versiculo_texto = 'Se em vocês habita o Espírito daquele que ressuscitou Jesus dentre os mortos, esse mesmo que ressuscitou Cristo dentre os mortos vivificará também o corpo mortal de vocês, por meio do seu Espírito, que habita em vocês.', versiculo_versao = 'NAA' where dia_ano = 100;
update devocional_anual set versiculo_texto = 'Então Jesus declarou: — Eu sou a ressurreição e a vida. Quem crê em mim, ainda que morra, viverá.', versiculo_versao = 'NAA' where dia_ano = 101;
update devocional_anual set versiculo_texto = 'em quem temos a redenção, a remissão dos pecados.', versiculo_versao = 'NAA' where dia_ano = 102;
update devocional_anual set versiculo_texto = 'Mas ele foi traspassado por causa das nossas transgressões e esmagado por causa das nossas iniquidades; o castigo que nos traz a paz estava sobre ele, e pelas suas feridas fomos sarados.', versiculo_versao = 'NAA' where dia_ano = 103;
update devocional_anual set versiculo_texto = 'carregando ele mesmo, em seu corpo, sobre o madeiro, os nossos pecados, para que nós, mortos para os pecados, vivamos para a justiça. Pelas feridas dele vocês foram sarados.', versiculo_versao = 'NAA' where dia_ano = 104;
update devocional_anual set versiculo_texto = 'De fato, segundo a lei, quase todas as coisas são purificadas com sangue; e sem derramamento de sangue não há remissão.', versiculo_versao = 'NAA' where dia_ano = 105;
update devocional_anual set versiculo_texto = 'Aquele que não conheceu pecado, Deus o fez pecado por nós, para que, nele, fôssemos feitos justiça de Deus.', versiculo_versao = 'NAA' where dia_ano = 106;
update devocional_anual set versiculo_texto = 'Mas Deus prova o seu próprio amor para conosco pelo fato de Cristo ter morrido por nós quando ainda éramos pecadores.', versiculo_versao = 'NAA' where dia_ano = 107;
update devocional_anual set versiculo_texto = 'Quando Jesus tomou o vinagre, disse: — Está consumado! E, inclinando a cabeça, entregou o espírito.', versiculo_versao = 'NAA' where dia_ano = 108;
update devocional_anual set versiculo_texto = 'O que eu quero é conhecer Cristo e o poder da sua ressurreição, tomar parte nos seus sofrimentos e me tornar como ele na sua morte,', versiculo_versao = 'NAA' where dia_ano = 109;
update devocional_anual set versiculo_texto = 'Assim também vocês considerem-se mortos para o pecado, mas vivos para Deus, em Cristo Jesus.', versiculo_versao = 'NAA' where dia_ano = 110;
update devocional_anual set versiculo_texto = 'Mas longe de mim gloriar-me, senão na cruz de nosso Senhor Jesus Cristo, pela qual o mundo está crucificado para mim, e eu estou crucificado para o mundo.', versiculo_versao = 'NAA' where dia_ano = 111;
update devocional_anual set versiculo_texto = 'ele se humilhou, tornando-se obediente até a morte, e morte de cruz.', versiculo_versao = 'NAA' where dia_ano = 112;
update devocional_anual set versiculo_texto = 'Mas Jesus dizia: — Pai, perdoa-lhes, porque não sabem o que fazem. Então, para repartir as roupas dele, lançaram sortes.', versiculo_versao = 'NAA' where dia_ano = 113;
update devocional_anual set versiculo_texto = 'E, adiantando-se um pouco, prostrou-se sobre o seu rosto, orando e dizendo: — Meu Pai, se é possível, que passe de mim este cálice! Contudo, não seja como eu quero, e sim como tu queres.', versiculo_versao = 'NAA' where dia_ano = 114;
update devocional_anual set versiculo_texto = 'Pois também Cristo padeceu, uma única vez, pelos pecados, o justo pelos injustos, para conduzir vocês a Deus; morto, sim, na carne, mas vivificado no espírito,', versiculo_versao = 'NAA' where dia_ano = 115;
update devocional_anual set versiculo_texto = 'Em verdade, em verdade lhes digo: se o grão de trigo, caindo na terra, não morrer, fica ele só; mas, se morrer, produz muito fruto.', versiculo_versao = 'NAA' where dia_ano = 116;
update devocional_anual set versiculo_texto = 'Então os olhos deles se abriram, e eles reconheceram Jesus; mas ele desapareceu da presença deles.', versiculo_versao = 'NAA' where dia_ano = 117;
update devocional_anual set versiculo_texto = 'e aquele que vive. Estive morto, mas eis que estou vivo para todo o sempre e tenho as chaves da morte e do inferno.', versiculo_versao = 'NAA' where dia_ano = 118;
update devocional_anual set versiculo_texto = 'Na verdade, toda disciplina, ao ser aplicada, não parece ser motivo de alegria, mas de tristeza. Porém, mais tarde, produz fruto pacífico aos que têm sido por ela exercitados, fruto de justiça.', versiculo_versao = 'NAA' where dia_ano = 119;
update devocional_anual set versiculo_texto = 'Por isso não desanimamos. Pelo contrário, mesmo que o nosso ser exterior se desgaste, o nosso ser interior se renova dia a dia. Porque a nossa leve e momentânea tribulação produz para nós um eterno peso de glória, acima de toda comparação,', versiculo_versao = 'NAA' where dia_ano = 120;
update devocional_anual set versiculo_texto = '— Honre o seu pai e a sua mãe, para que você tenha uma longa vida na terra que o SENHOR, seu Deus, lhe dá.', versiculo_versao = 'NAA' where dia_ano = 121;
update devocional_anual set versiculo_texto = 'Paguem a todos o que lhes é devido: a quem tributo, tributo; a quem imposto, imposto; a quem respeito, respeito; a quem honra, honra.', versiculo_versao = 'NAA' where dia_ano = 122;
update devocional_anual set versiculo_texto = 'Tratem todos com honra, amem os irmãos na fé, temam a Deus e honrem o rei.', versiculo_versao = 'NAA' where dia_ano = 123;
update devocional_anual set versiculo_texto = 'Honre o SENHOR com os seus bens e com as primícias de toda a sua renda;', versiculo_versao = 'NAA' where dia_ano = 124;
update devocional_anual set versiculo_texto = 'Ele me invocará, e eu lhe responderei; na sua angústia eu estarei com ele; eu o livrarei e o glorificarei.', versiculo_versao = 'NAA' where dia_ano = 125;
update devocional_anual set versiculo_texto = 'Devem ser considerados merecedores de pagamento em dobro os presbíteros que presidem bem, especialmente os que se esforçam na pregação da palavra e no ensino.', versiculo_versao = 'NAA' where dia_ano = 126;
update devocional_anual set versiculo_texto = 'A mulher bondosa alcança honra; os poderosos adquirem riqueza.', versiculo_versao = 'NAA' where dia_ano = 127;
update devocional_anual set versiculo_texto = 'Mais vale o bom nome do que as muitas riquezas; ser estimado é melhor do que a prata e o ouro.', versiculo_versao = 'NAA' where dia_ano = 128;
update devocional_anual set versiculo_texto = '“Honre o seu pai e a sua mãe”, que é o primeiro mandamento com promessa, “para que tudo corra bem com você, e você tenha uma longa vida sobre a terra”.', versiculo_versao = 'NAA' where dia_ano = 129;
update devocional_anual set versiculo_texto = 'Enganosa é a graça, e vã é a formosura, mas a mulher que teme o SENHOR, essa será louvada.', versiculo_versao = 'NAA' where dia_ano = 130;
update devocional_anual set versiculo_texto = 'Fique em pé na presença dos idosos, honre a presença do ancião e tema o seu Deus. Eu sou o SENHOR.', versiculo_versao = 'NAA' where dia_ano = 131;
update devocional_anual set versiculo_texto = 'Porque Deus disse: “Honre o seu pai e a sua mãe.” E: “Quem maldisser o seu pai ou a sua mãe seja punido de morte.” Vocês, porém, dizem que, se alguém disser ao seu pai ou à sua mãe: “A ajuda que você poderia receber de mim é oferta ao Senhor”, esse não precisará mais honrar os seus pais. E, assim, vocês invalidam a palavra de Deus, por causa da tradição de vocês.', versiculo_versao = 'NAA' where dia_ano = 132;
update devocional_anual set versiculo_texto = 'Amem uns aos outros com amor fraternal. Quanto à honra, deem sempre preferência aos outros.', versiculo_versao = 'NAA' where dia_ano = 133;
update devocional_anual set versiculo_texto = '— Portanto, o SENHOR, o Deus de Israel, diz: “Na verdade, eu prometi que a sua casa e a casa de seu pai andariam diante de mim para sempre. Mas agora o SENHOR diz: Longe de mim tal coisa, porque honrarei aqueles que me honram, porém desprezarei os que me desprezam.', versiculo_versao = 'NAA' where dia_ano = 134;
update devocional_anual set versiculo_texto = 'O temor do SENHOR é instrução na sabedoria, e a humildade precede a honra.', versiculo_versao = 'NAA' where dia_ano = 135;
update devocional_anual set versiculo_texto = 'Também falarei dos teus testemunhos na presença dos reis e não me envergonharei.', versiculo_versao = 'NAA' where dia_ano = 136;
update devocional_anual set versiculo_texto = 'Antes da ruína, o coração humano se gaba, mas a humildade precede a honra.', versiculo_versao = 'NAA' where dia_ano = 137;
update devocional_anual set versiculo_texto = 'Porque vocês foram comprados por preço. Agora, pois, glorifiquem a Deus no corpo de vocês.', versiculo_versao = 'NAA' where dia_ano = 138;
update devocional_anual set versiculo_texto = 'Quem oprime o pobre insulta aquele que o criou, mas o que se compadece do necessitado honra a Deus.', versiculo_versao = 'NAA' where dia_ano = 139;
update devocional_anual set versiculo_texto = 'Digno de honra entre todos seja o matrimônio, bem como o leito conjugal sem mácula; porque Deus julgará os impuros e os adúlteros.', versiculo_versao = 'NAA' where dia_ano = 140;
update devocional_anual set versiculo_texto = 'Mas entre vocês não é assim; pelo contrário, quem quiser tornar-se grande entre vocês, que se coloque a serviço dos outros; e quem quiser ser o primeiro entre vocês, que seja servo de todos.', versiculo_versao = 'NAA' where dia_ano = 141;
update devocional_anual set versiculo_texto = 'Não façam nada por interesse pessoal ou vaidade, mas por humildade, cada um considerando os outros superiores a si mesmo,', versiculo_versao = 'NAA' where dia_ano = 142;
update devocional_anual set versiculo_texto = 'aquele que, a seus olhos, tem por desprezível ao que merece reprovação, mas honra os que temem o SENHOR; aquele que jura e cumpre o que prometeu, mesmo com prejuízo próprio;', versiculo_versao = 'NAA' where dia_ano = 143;
update devocional_anual set versiculo_texto = 'Que a palavra de vocês seja: Sim, sim; não, não. O que passar disto vem do Maligno.', versiculo_versao = 'NAA' where dia_ano = 144;
update devocional_anual set versiculo_texto = 'O SENHOR detesta lábios mentirosos, mas aqueles que praticam a verdade são o seu prazer.', versiculo_versao = 'NAA' where dia_ano = 145;
update devocional_anual set versiculo_texto = 'Porque o SENHOR Deus é sol e escudo; o SENHOR dá graça e glória; não recusa nenhum bem aos que andam retamente.', versiculo_versao = 'NAA' where dia_ano = 146;
update devocional_anual set versiculo_texto = 'Fizeste-o, no entanto, por um pouco, menor do que Deus e de glória e de honra o coroaste.', versiculo_versao = 'NAA' where dia_ano = 147;
update devocional_anual set versiculo_texto = 'O orgulho do ser humano o abaterá, mas o humilde de espírito obterá honra.', versiculo_versao = 'NAA' where dia_ano = 148;
update devocional_anual set versiculo_texto = 'Peço igualmente aos jovens: estejam sujeitos aos que são mais velhos. Que todos se revistam de humildade no trato de uns com os outros, porque “Deus resiste aos soberbos, mas dá graça aos humildes.”', versiculo_versao = 'NAA' where dia_ano = 149;
update devocional_anual set versiculo_texto = 'Porque todo o que se exalta será humilhado; e o que se humilha será exaltado.', versiculo_versao = 'NAA' where dia_ano = 150;
update devocional_anual set versiculo_texto = 'Assim, pois, se alguém se purificar destes erros, será utensílio para honra, santificado e útil ao seu senhor, estando preparado para toda boa obra.', versiculo_versao = 'NAA' where dia_ano = 151;
update devocional_anual set versiculo_texto = 'Mas vocês receberão poder, ao descer sobre vocês o Espírito Santo, e serão minhas testemunhas tanto em Jerusalém como em toda a Judeia e Samaria e até os confins da terra.', versiculo_versao = 'NAA' where dia_ano = 152;
update devocional_anual set versiculo_texto = 'E eu pedirei ao Pai, e ele lhes dará outro Consolador, a fim de que esteja com vocês para sempre: é o Espírito da verdade, que o mundo não pode receber, porque não o vê, nem o conhece. Vocês o conhecem, porque ele habita com vocês e estará em vocês.', versiculo_versao = 'NAA' where dia_ano = 153;
update devocional_anual set versiculo_texto = 'Pois todos os que são guiados pelo Espírito de Deus são filhos de Deus.', versiculo_versao = 'NAA' where dia_ano = 154;
update devocional_anual set versiculo_texto = 'O próprio Espírito confirma ao nosso espírito que somos filhos de Deus.', versiculo_versao = 'NAA' where dia_ano = 155;
update devocional_anual set versiculo_texto = 'Mas o fruto do Espírito é: amor, alegria, paz, longanimidade, benignidade, bondade, fidelidade, mansidão, domínio próprio. Contra estas coisas não há lei.', versiculo_versao = 'NAA' where dia_ano = 156;
update devocional_anual set versiculo_texto = 'Ao cumprir-se o dia de Pentecostes, estavam todos reunidos no mesmo lugar. De repente, veio do céu um som, como de um vento impetuoso, e encheu toda a casa onde estavam sentados. E apareceram, distribuídas entre eles, línguas, como de fogo, as quais pousaram sobre cada um deles. Todos ficaram cheios do Espírito Santo e começaram a falar em outras línguas, segundo o Espírito lhes concedia que falassem.', versiculo_versao = 'NAA' where dia_ano = 157;
update devocional_anual set versiculo_texto = 'A manifestação do Espírito é concedida a cada um visando um fim proveitoso.', versiculo_versao = 'NAA' where dia_ano = 158;
update devocional_anual set versiculo_texto = 'Porém, quando vier o Espírito da verdade, ele os guiará em toda a verdade. Ele não falará por si mesmo, mas dirá tudo o que ouvir e anunciará a vocês as coisas que estão para acontecer.', versiculo_versao = 'NAA' where dia_ano = 159;
update devocional_anual set versiculo_texto = 'E não se embriaguem com vinho, pois isso leva à devassidão, mas deixem-se encher do Espírito,', versiculo_versao = 'NAA' where dia_ano = 160;
update devocional_anual set versiculo_texto = 'Vocês não sabem que são santuário de Deus e que o Espírito de Deus habita em vocês?', versiculo_versao = 'NAA' where dia_ano = 161;
update devocional_anual set versiculo_texto = 'Ora, este Senhor é o Espírito; e onde está o Espírito do Senhor, aí há liberdade.', versiculo_versao = 'NAA' where dia_ano = 162;
update devocional_anual set versiculo_texto = 'Da mesma maneira, também o Espírito nos ajuda em nossa fraqueza. Porque não sabemos orar como convém, mas o próprio Espírito intercede por nós com gemidos inexprimíveis.', versiculo_versao = 'NAA' where dia_ano = 163;
update devocional_anual set versiculo_texto = '“E acontecerá, depois disso, que derramarei o meu Espírito sobre toda a humanidade. Os filhos e as filhas de vocês profetizarão, os seus velhos sonharão, e os seus jovens terão visões.', versiculo_versao = 'NAA' where dia_ano = 164;
update devocional_anual set versiculo_texto = 'Tendo eles orado, tremeu o lugar onde estavam reunidos. Todos ficaram cheios do Espírito Santo e, com ousadia, anunciavam a palavra de Deus.', versiculo_versao = 'NAA' where dia_ano = 165;
update devocional_anual set versiculo_texto = 'Digo, porém, o seguinte: vivam no Espírito e vocês jamais satisfarão os desejos da carne.', versiculo_versao = 'NAA' where dia_ano = 166;
update devocional_anual set versiculo_texto = 'O vento sopra onde quer, você ouve o barulho que ele faz, mas não sabe de onde ele vem, nem para onde vai; assim é todo o que é nascido do Espírito.', versiculo_versao = 'NAA' where dia_ano = 167;
update devocional_anual set versiculo_texto = 'Vocês, porém, não estão na carne, mas no Espírito, se de fato o Espírito de Deus habita em vocês. E, se alguém não tem o Espírito de Cristo, esse tal não é dele.', versiculo_versao = 'NAA' where dia_ano = 168;
update devocional_anual set versiculo_texto = 'E não entristeçam o Espírito Santo de Deus, no qual vocês foram selados para o dia da redenção.', versiculo_versao = 'NAA' where dia_ano = 169;
update devocional_anual set versiculo_texto = 'Não apaguem o Espírito.', versiculo_versao = 'NAA' where dia_ano = 170;
update devocional_anual set versiculo_texto = 'Assim, a igreja tinha paz por toda a Judeia, Galileia e Samaria, edificando-se e caminhando no temor do Senhor; e, no consolo do Espírito Santo, crescia em número.', versiculo_versao = 'NAA' where dia_ano = 171;
update devocional_anual set versiculo_texto = 'Ora, a esperança não nos deixa decepcionados, porque o amor de Deus é derramado em nosso coração pelo Espírito Santo, que nos foi dado.', versiculo_versao = 'NAA' where dia_ano = 172;
update devocional_anual set versiculo_texto = 'Deus, porém, revelou isso a nós por meio do Espírito. Porque o Espírito sonda todas as coisas, até mesmo as profundezas de Deus.', versiculo_versao = 'NAA' where dia_ano = 173;
update devocional_anual set versiculo_texto = 'Ora, se vocês, que são maus, sabem dar coisas boas aos seus filhos, quanto mais o Pai celeste dará o Espírito Santo aos que lhe pedirem!', versiculo_versao = 'NAA' where dia_ano = 174;
update devocional_anual set versiculo_texto = 'Nisto conhecemos que permanecemos nele e que ele permanece em nós: pelo fato de nos ter dado do seu Espírito.', versiculo_versao = 'NAA' where dia_ano = 175;
update devocional_anual set versiculo_texto = 'ele nos salvou, não por obras de justiça praticadas por nós, mas segundo a sua misericórdia. Ele nos salvou mediante o lavar regenerador e renovador do Espírito Santo,', versiculo_versao = 'NAA' where dia_ano = 176;
update devocional_anual set versiculo_texto = 'Mas o Consolador, o Espírito Santo, que o Pai enviará em meu nome, esse ensinará a vocês todas as coisas e fará com que se lembrem de tudo o que eu lhes disse.', versiculo_versao = 'NAA' where dia_ano = 177;
update devocional_anual set versiculo_texto = 'Enquanto eles estavam adorando o Senhor e jejuando, o Espírito Santo disse: — Separem-me, agora, Barnabé e Saulo para a obra a que os tenho chamado.', versiculo_versao = 'NAA' where dia_ano = 178;
update devocional_anual set versiculo_texto = 'que também pôs o seu selo em nós e nos deu o penhor do Espírito em nosso coração.', versiculo_versao = 'NAA' where dia_ano = 179;
update devocional_anual set versiculo_texto = 'Nele também vocês, depois que ouviram a palavra da verdade, o evangelho da salvação, tendo nele também crido, receberam o selo do Espírito Santo da promessa. O Espírito é o penhor da nossa herança, até o resgate da sua propriedade, em louvor da sua glória.', versiculo_versao = 'NAA' where dia_ano = 180;
update devocional_anual set versiculo_texto = 'Ele prosseguiu e me disse: — Esta é a palavra do SENHOR a Zorobabel: “Não por força nem por poder, mas pelo meu Espírito”, diz o SENHOR dos Exércitos.', versiculo_versao = 'NAA' where dia_ano = 181;
